import{_ as t,o as a,c as s,ag as o}from"./chunks/framework.BZohXCq9.js";const u=JSON.parse('{"title":"Studio Agent System — Complete Guide","description":"","frontmatter":{},"headers":[],"relativePath":"studio-agent-guide.md","filePath":"studio-agent-guide.md","lastUpdated":1773112636000}'),d={name:"studio-agent-guide.md"};function n(i,e,r,l,c,p){return a(),s("div",null,[...e[0]||(e[0]=[o(`<h1 id="studio-agent-system-—-complete-guide" tabindex="-1">Studio Agent System — Complete Guide <a class="header-anchor" href="#studio-agent-system-—-complete-guide" aria-label="Permalink to &quot;Studio Agent System — Complete Guide&quot;">​</a></h1><p>How the AI studio assistant works, where it gets its knowledge, and how to make it smarter.</p><hr><h2 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h2><p>When a user sends a message in the studio, the server builds a system prompt from multiple sources and sends it to the LLM alongside 24 tool definitions. The agent reads this prompt, decides what to do, and calls tools to make changes.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User message arrives</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>Server builds system prompt:</span></span>
<span class="line"><span>    1. TOOL_CORE_PROMPT          ← Identity + behavior rules (hardcoded)</span></span>
<span class="line"><span>    2. 1-3 SKILL.md files        ← Domain knowledge (selected by keyword/panel)</span></span>
<span class="line"><span>    3. Template catalog summary  ← Available templates list</span></span>
<span class="line"><span>    4. World summary             ← Current world state (from client)</span></span>
<span class="line"><span>    5. Studio context            ← Active panel + selected entity</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>Sent to LLM with 24 tool definitions (JSON Schema)</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>LLM responds with text + tool calls</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>Client executes tools against the editor store</span></span></code></pre></div><h2 id="where-everything-lives" tabindex="-1">Where Everything Lives <a class="header-anchor" href="#where-everything-lives" aria-label="Permalink to &quot;Where Everything Lives&quot;">​</a></h2><table tabindex="0"><thead><tr><th>What</th><th>Location</th><th>When the agent sees it</th></tr></thead><tbody><tr><td>Core identity + rules</td><td><code>packages/server/src/lib/studio-tools/system-prompt.ts</code></td><td>Every request</td></tr><tr><td>Domain knowledge</td><td><code>packages/server/skills/&lt;name&gt;/SKILL.md</code></td><td>When keyword/panel matches</td></tr><tr><td>Code/config templates</td><td><code>packages/server/skills/&lt;name&gt;/templates/&lt;id&gt;/</code></td><td>When agent calls list_templates or install_template</td></tr><tr><td>Template catalog index</td><td><code>packages/server/skills/_catalog.json</code></td><td>Every request (summary)</td></tr><tr><td>Tool definitions</td><td><code>packages/server/src/lib/studio-tools/definitions.ts</code></td><td>Every request (as function schemas)</td></tr><tr><td>World summary</td><td><code>packages/app/src/features/studio/lib/world-summary.ts</code></td><td>Every request (built from current editor state)</td></tr><tr><td>YUI component library</td><td><code>packages/app/src/lib/yui/</code></td><td>Available at runtime in compiled TSX (not in prompt)</td></tr><tr><td>Skill selection logic</td><td><code>packages/server/src/lib/studio-skills/index.ts</code></td><td>N/A (server-side routing)</td></tr></tbody></table><h2 id="how-skill-selection-works" tabindex="-1">How Skill Selection Works <a class="header-anchor" href="#how-skill-selection-works" aria-label="Permalink to &quot;How Skill Selection Works&quot;">​</a></h2><p>Each request loads 1-3 skills based on two signals:</p><ol><li><strong>Active panel</strong> — Which studio panel is open (lorebook, variables, rules, canvas, code-view, audio)</li><li><strong>User message keywords</strong> — Regex patterns match against the message text</li></ol><table tabindex="0"><thead><tr><th>Skill</th><th>Loaded when panel is...</th><th>Or when message contains...</th></tr></thead><tbody><tr><td>entries</td><td>lorebook</td><td>character, entry, greeting, prompt, persona, npc</td></tr><tr><td>variables</td><td>variables</td><td>variable, stat, health, mana, gold, inventory, hp</td></tr><tr><td>rules</td><td>rules</td><td>rule, trigger, event, when, condition, directive</td></tr><tr><td>lore</td><td>lorebook</td><td>lore, worldbuild, canon, faction, kingdom, history</td></tr><tr><td>audio</td><td>audio</td><td>audio, music, bgm, sfx, sound, ambient</td></tr><tr><td>components</td><td>canvas, components</td><td>component, stat-bar, widget, image-panel, header</td></tr><tr><td>tsx</td><td>code-view</td><td>tsx, custom, renderer, react, interactive, visual</td></tr><tr><td>front-ui</td><td>canvas, code-view</td><td>hud, dashboard, layout, theme, blueprint, panel</td></tr></tbody></table><p>Maximum 3 skills per request. Default (nothing matched): entries.</p><p>The selection logic is in <code>packages/server/src/lib/studio-skills/index.ts</code> → <code>selectSkills()</code>. To add a new keyword trigger, add a regex pattern and update the routing logic.</p><h2 id="how-to-make-the-agent-smarter" tabindex="-1">How to Make the Agent Smarter <a class="header-anchor" href="#how-to-make-the-agent-smarter" aria-label="Permalink to &quot;How to Make the Agent Smarter&quot;">​</a></h2><h3 id="_1-improve-domain-knowledge-→-edit-skill-md" tabindex="-1">1. Improve domain knowledge → Edit SKILL.md <a class="header-anchor" href="#_1-improve-domain-knowledge-→-edit-skill-md" aria-label="Permalink to &quot;1. Improve domain knowledge → Edit SKILL.md&quot;">​</a></h3><p>Each <code>SKILL.md</code> is injected directly into the system prompt when its skill is selected. This is the agent&#39;s primary knowledge source.</p><p><strong>File:</strong> <code>packages/server/skills/&lt;name&gt;/SKILL.md</code></p><p><strong>Guidelines:</strong></p><ul><li>Keep under ~150 lines (the prompt has limited space — 3 skills may load at once)</li><li>Use tables for quick lookup (role mapping, prop reference, etc.)</li><li>Focus on decision-making: &quot;when to use X vs Y&quot;, &quot;what good X looks like&quot;</li><li>Include short inline examples where helpful</li><li>Don&#39;t repeat what the tool definitions already say (parameter names, types)</li><li>Test changes by chatting with the agent and checking if it follows the new guidance</li></ul><p><strong>Example — adding character writing guidance to entries/SKILL.md:</strong></p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">### character</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Include: personality traits (3-5), speech patterns, appearance summary,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">backstory hooks, key relationships. Write in third person: &quot;{{char}} is a...&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Avoid: walls of text. Each paragraph should cover one aspect.</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Good: &quot;Aria speaks in clipped military cadence, softening only around children.&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Bad: &quot;Aria is nice and talks normally.&quot;</span></span></code></pre></div><h3 id="_2-add-detailed-guides-→-templates-folder-with-md-files" tabindex="-1">2. Add detailed guides → templates/ folder with .md files <a class="header-anchor" href="#_2-add-detailed-guides-→-templates-folder-with-md-files" aria-label="Permalink to &quot;2. Add detailed guides → templates/ folder with .md files&quot;">​</a></h3><p>For content too long for SKILL.md (writing guides, best practices, design patterns), put them in the skill&#39;s templates/ folder as markdown files.</p><p><strong>Location:</strong> <code>packages/server/skills/&lt;name&gt;/templates/&lt;guide-id&gt;/</code></p><p><strong>Structure:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>skills/entries/templates/character-writing-guide/</span></span>
<span class="line"><span>├── meta.json      ← { &quot;name&quot;: &quot;Character Writing Guide&quot;, &quot;surface&quot;: &quot;pattern&quot;, &quot;tags&quot;: [&quot;writing&quot;, &quot;character&quot;] }</span></span>
<span class="line"><span>└── guide.md       ← Full guide content (can be longer — only loaded on demand)</span></span></code></pre></div><p>These are NOT auto-injected into the prompt. The agent discovers them via <code>list_templates</code> and reads them when relevant. Register in <code>_catalog.json</code> so the agent knows they exist.</p><h3 id="_3-add-code-config-templates-→-templates-folder-with-tsx-json" tabindex="-1">3. Add code/config templates → templates/ folder with .tsx/.json <a class="header-anchor" href="#_3-add-code-config-templates-→-templates-folder-with-tsx-json" aria-label="Permalink to &quot;3. Add code/config templates → templates/ folder with .tsx/.json&quot;">​</a></h3><p>Pre-built UI patterns the agent can reference or install directly.</p><p><strong>Location:</strong> <code>packages/server/skills/&lt;name&gt;/templates/&lt;template-id&gt;/</code></p><p><strong>Structure:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>skills/tsx/templates/game-hud-renderer/</span></span>
<span class="line"><span>├── meta.json       ← Metadata (name, description, tags, surface, requires)</span></span>
<span class="line"><span>└── renderer.tsx    ← TSX code (message renderer)</span></span></code></pre></div><p><strong>Surface types and filenames:</strong></p><table tabindex="0"><thead><tr><th>Surface</th><th>Filename</th><th>What it installs as</th></tr></thead><tbody><tr><td>message-renderer</td><td><code>renderer.tsx</code></td><td>World&#39;s message renderer</td></tr><tr><td>custom-component</td><td><code>component.tsx</code></td><td>Full-screen custom component</td></tr><tr><td>ui-blueprint</td><td><code>blueprint.json</code></td><td>World&#39;s uiBlueprint</td></tr><tr><td>world</td><td><code>template.json</code></td><td>Merges entries/variables/rules/components</td></tr><tr><td>pattern</td><td><code>renderer.tsx</code> or <code>guide.md</code></td><td>Reusable pattern (greeting flow, etc.)</td></tr></tbody></table><p><strong>After creating the template:</strong></p><ol><li>Add an entry to <code>packages/server/skills/_catalog.json</code></li><li>The agent automatically sees it in the template catalog summary</li><li>The agent can install it via the <code>install_template</code> tool</li></ol><p>See <code>packages/server/skills/GUIDELINES.md</code> for the full meta.json format spec.</p><h3 id="_4-add-yui-components-→-packages-app-src-lib-yui" tabindex="-1">4. Add YUI components → packages/app/src/lib/yui/ <a class="header-anchor" href="#_4-add-yui-components-→-packages-app-src-lib-yui" aria-label="Permalink to &quot;4. Add YUI components → packages/app/src/lib/yui/&quot;">​</a></h3><p>Pre-built React components available as <code>YUI.*</code> in all custom components and message renderers. These are app-level code (not skill files) — they ship with the build.</p><p><strong>To add a new component:</strong></p><ol><li>Create <code>packages/app/src/lib/yui/&lt;component-name&gt;.tsx</code> with a named export</li><li>Add it to <code>packages/app/src/lib/yui/index.ts</code> in the YUI object</li><li>Document it in <code>packages/server/skills/tsx/SKILL.md</code> (the YUI Component Library section)</li></ol><p>No other changes needed — it&#39;s automatically injected into the compiled TSX scope via the <code>new Function(&quot;React&quot;, &quot;useYumina&quot;, &quot;Icons&quot;, &quot;YUI&quot;, ...)</code> call in <code>tsx-compiler.ts</code>.</p><p>See <code>packages/app/src/lib/yui/GUIDELINES.md</code> for component design rules.</p><h3 id="_5-add-new-tools-→-definitions-ts-tool-executor-ts" tabindex="-1">5. Add new tools → definitions.ts + tool-executor.ts <a class="header-anchor" href="#_5-add-new-tools-→-definitions-ts-tool-executor-ts" aria-label="Permalink to &quot;5. Add new tools → definitions.ts + tool-executor.ts&quot;">​</a></h3><p>If the agent needs a genuinely new capability (not just better knowledge), add a tool.</p><p><strong>Server side:</strong> <code>packages/server/src/lib/studio-tools/definitions.ts</code></p><ul><li>Add to <code>READ_TOOLS</code> (auto-execute) or <code>WRITE_TOOLS</code> (requires approval)</li><li>Define name, description, and JSON Schema parameters</li></ul><p><strong>Client side:</strong> <code>packages/app/src/features/studio/lib/tool-executor.ts</code></p><ul><li>Add handler in <code>executeReadTool()</code> or <code>executeWriteTool()</code></li></ul><p><strong>Client types:</strong> <code>packages/app/src/features/studio/lib/types.ts</code></p><ul><li>Add read tool names to <code>READ_TOOL_NAMES</code> set</li></ul><h3 id="_6-change-core-behavior-→-system-prompt-ts" tabindex="-1">6. Change core behavior → system-prompt.ts <a class="header-anchor" href="#_6-change-core-behavior-→-system-prompt-ts" aria-label="Permalink to &quot;6. Change core behavior → system-prompt.ts&quot;">​</a></h3><p>The <code>TOOL_CORE_PROMPT</code> in <code>packages/server/src/lib/studio-tools/system-prompt.ts</code> defines the agent&#39;s identity, workflow (UNDERSTAND → PLAN → EXECUTE), and tool usage rules. Edit this to change fundamental behavior — not domain knowledge.</p><h2 id="quick-reference-i-want-to" tabindex="-1">Quick Reference: &quot;I want to...&quot; <a class="header-anchor" href="#quick-reference-i-want-to" aria-label="Permalink to &quot;Quick Reference: &quot;I want to...&quot;&quot;">​</a></h2><table tabindex="0"><thead><tr><th>I want to...</th><th>Do this</th></tr></thead><tbody><tr><td>Teach the agent about a concept</td><td>Edit the relevant <code>SKILL.md</code></td></tr><tr><td>Add a writing/design guide</td><td>Add a <code>.md</code> template in <code>skills/&lt;name&gt;/templates/</code></td></tr><tr><td>Add a code template</td><td>Add a <code>.tsx</code>/<code>.json</code> template in <code>skills/&lt;name&gt;/templates/</code></td></tr><tr><td>Add a reusable UI component</td><td>Add to <code>packages/app/src/lib/yui/</code></td></tr><tr><td>Add a new agent tool</td><td>Add to <code>definitions.ts</code> + <code>tool-executor.ts</code></td></tr><tr><td>Change how skills are selected</td><td>Edit <code>selectSkills()</code> in <code>studio-skills/index.ts</code></td></tr><tr><td>Change the agent&#39;s core behavior</td><td>Edit <code>TOOL_CORE_PROMPT</code> in <code>system-prompt.ts</code></td></tr><tr><td>Add a new skill category</td><td>Create <code>skills/&lt;name&gt;/SKILL.md</code>, add regex to <code>selectSkills()</code></td></tr></tbody></table><h2 id="size-guidelines" tabindex="-1">Size Guidelines <a class="header-anchor" href="#size-guidelines" aria-label="Permalink to &quot;Size Guidelines&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Content type</th><th>Max size</th><th>Why</th></tr></thead><tbody><tr><td>SKILL.md</td><td>~150 lines</td><td>Injected into prompt, up to 3 at once. Keep concise.</td></tr><tr><td>TOOL_CORE_PROMPT</td><td>~30 lines</td><td>Loaded on every single request. Must be tight.</td></tr><tr><td>Template .tsx/.json</td><td>No hard limit</td><td>Only loaded when agent reads/installs. Can be large.</td></tr><tr><td>Template guide .md</td><td>No hard limit</td><td>Only loaded on demand. Can be detailed.</td></tr><tr><td>_catalog.json entries</td><td>~1 line each</td><td>Summary injected every request. Keep descriptions short.</td></tr></tbody></table><h2 id="conversation-persistence" tabindex="-1">Conversation Persistence <a class="header-anchor" href="#conversation-persistence" aria-label="Permalink to &quot;Conversation Persistence&quot;">​</a></h2><p>Studio conversations are saved per world in the <code>studio_conversations</code> database table. The UI has a conversation switcher (MessageSquare icon in the chat header):</p><ul><li><strong>Auto-load</strong>: Most recent conversation loads when studio opens</li><li><strong>Auto-save</strong>: Saves 2 seconds after messages change</li><li><strong>Auto-create</strong>: First message creates a new conversation</li><li><strong>Switch</strong>: Click any conversation to load its history</li><li><strong>Delete</strong>: Hover to reveal delete button</li></ul><p>The agent sees the full conversation history (messages, tool calls, results, proposals). This IS the agent&#39;s memory — no separate memory system needed.</p><h2 id="file-attachments" tabindex="-1">File Attachments <a class="header-anchor" href="#file-attachments" aria-label="Permalink to &quot;File Attachments&quot;">​</a></h2><p>Users can attach files in the studio chat:</p><table tabindex="0"><thead><tr><th>File type</th><th>How it&#39;s handled</th></tr></thead><tbody><tr><td>Images (.png, .jpg, .webp, .gif)</td><td>Uploaded to S3, sent as multimodal content to LLM</td></tr><tr><td>Code files (.tsx, .jsx, .ts, .js, .json, .md, .txt, .html, .css)</td><td>Read client-side, injected as fenced code blocks in message text</td></tr></tbody></table><p>The agent is instructed to adapt attached code to Yumina format (strip imports, convert to Yumina TSX rules, wire up useYumina()).</p>`,66)])])}const m=t(d,[["render",n]]);export{u as __pageData,m as default};
